"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[74008],{60889(e,t,i){i.r(t),i.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>u,frontMatter:()=>o,metadata:()=>s,toc:()=>d});let s=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/subsurface-rights-ifrs-16-2fb78d1eba","title":"Subsurface Rights (IFRS 16)","description":"June 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/Subsurface Rights (IFRS 16).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/subsurface-rights-ifrs-16-2fb78d1eba","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/subsurface-rights-ifrs-16-2fb78d1eba","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":7,"frontMatter":{"id":"subsurface-rights-ifrs-16-2fb78d1eba","title":"Subsurface Rights (IFRS 16)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/subsurface-rights-ifrs-16-2fb78d1eba","sidebar_position":7},"sidebar":"knowledgeSidebar","previous":{"title":"Sale and Leaseback with Variable Payments (IFRS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/sale-and-leaseback-with-variable-pay-244a5fb586"},"next":{"title":"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768"}}');var a=i(74848),n=i(28453);let o={id:"subsurface-rights-ifrs-16-2fb78d1eba",title:"Subsurface Rights (IFRS 16)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/subsurface-rights-ifrs-16-2fb78d1eba",sidebar_position:7},r="Subsurface Rights (IFRS 16)",h={},d=[{value:"Which IFRS Standard does an entity consider first?",id:"which-ifrs-standard-does-an-entity-consider-first",level:2},{value:"The definition of a lease",id:"the-definition-of-a-lease",level:2},{value:"Identified asset",id:"identified-asset",level:2},{value:"Right to obtain substantially all the economic benefits from use",id:"right-to-obtain-substantially-all-the-economic-benefits-from-use",level:2},{value:"Right to direct the use",id:"right-to-direct-the-use",level:2}];function c(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,n.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"subsurface-rights-ifrs-16",children:"Subsurface Rights (IFRS 16)"})}),"\n",(0,a.jsx)(t.p,{children:"June 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about a particular contract for subsurface rights. In the contract described in the request, a pipeline operator (customer) obtains the right to place an oil pipeline in underground space for 20 years in exchange for consideration. The contract specifies the exact location and dimensions (path, width and depth) of the underground space within which the pipeline will be placed. The landowner retains the right to use the surface of the land above the pipeline, but it has no right to access or otherwise change the use of the specified underground space  throughout the 20-year period of use. The customer has the right to perform inspection, repairs and maintenance work (including replacing damaged sections of the pipeline when necessary)."}),"\n",(0,a.jsx)(t.p,{children:"The request asked whether IFRS 16, IAS 38 Intangible Assets or another IFRS Standard applies in accounting for the contract."}),"\n",(0,a.jsx)(t.h2,{id:"which-ifrs-standard-does-an-entity-consider-first",children:"Which IFRS Standard does an entity consider first?"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 3 of IFRS 16 requires an entity to apply IFRS 16 to all leases, with limited exceptions. Paragraph 9 of IFRS 16 states: \u2018At inception of a contract, an entity shall assess whether the contract is, or contains, a lease\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the contract described in the request, none of the exceptions in paragraphs 3 and 4 of IFRS 16 apply\u2014in particular, the Committee noted that the underground space is tangible. Accordingly, if the contract contains a lease, IFRS 16 applies to that lease. If the contract does not contain a lease, the entity would then consider which other IFRS Standard applies."}),"\n",(0,a.jsx)(t.p,{children:"The Committee therefore concluded that the entity first considers whether the contract contains a lease as defined in IFRS 16."}),"\n",(0,a.jsx)(t.h2,{id:"the-definition-of-a-lease",children:"The definition of a lease"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 9 of IFRS 16 states that \u2018a contract is, or contains, a lease if the contract conveys the right to control the use of an identified asset for a period of time in exchange for consideration\u2019."}),"\n",(0,a.jsx)(t.p,{children:"Applying paragraph B9 of IFRS 16, to meet the definition of a lease the customer must have both:"}),"\n",(0,a.jsx)(t.p,{children:"a. the right to obtain substantially all the economic benefits from use of an identified asset throughout the period of use; and\nb. the right to direct the use of the identified asset throughout the period of use."}),"\n",(0,a.jsx)(t.h2,{id:"identified-asset",children:"Identified asset"}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs B13\u2013B20 of IFRS 16 provide application guidance on an identified asset. Paragraph B20 states that a \u2018capacity portion of an asset is an identified asset if it is physically distinct\u2019. But \u2018a customer does not have the right to use an identified asset if the supplier has the substantive right to substitute the asset throughout the period of use\u2019 (paragraph B14)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the contract described in the request, the specified underground space is physically distinct from the remainder of the land. The contract\u2019s specifications include the path, width and depth of the pipeline, thereby defining a physically distinct underground space. The space being underground does not in itself affect whether it is an identified asset\u2014the specified underground space is physically distinct in the same way that a specified area of space on the land\u2019s surface would be physically distinct."}),"\n",(0,a.jsx)(t.p,{children:"The landowner does not have the right to substitute the underground space throughout the period of use. Consequently, the Committee concluded that the specified underground space is an identified asset as described in paragraphs B13\u2013B20."}),"\n",(0,a.jsx)(t.h2,{id:"right-to-obtain-substantially-all-the-economic-benefits-from-use",children:"Right to obtain substantially all the economic benefits from use"}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs B21\u2013B23 of IFRS 16 provide application guidance on the right to obtain substantially all the economic benefits from use of an identified asset throughout the period of use. Paragraph B21 specifies that a customer can have that right, for example, by having exclusive use of the identified asset throughout the period of use."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the contract described in the request, the customer has the right to obtain substantially all the economic benefits from use of the specified underground space throughout the 20-year period of use. The customer has exclusive use of the specified underground space throughout that period of use."}),"\n",(0,a.jsx)(t.h2,{id:"right-to-direct-the-use",children:"Right to direct the use"}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs B24-B30 of IFRS 16 provide application guidance on the right to direct the use of an identified asset throughout the period of use. Paragraph B24 specifies that a customer has that right if either:"}),"\n",(0,a.jsx)(t.p,{children:"a. the customer has the right to direct how and for what purpose the asset is used throughout the period of use; or\nb. the relevant decisions about how and for what purpose the asset is used are predetermined and (i) the customer has the right to operate the asset throughout the period of use, without the supplier having the right to change those operating instructions; or (ii) the customer designed the asset in a way that predetermines how and for what purpose the asset will be used throughout the period of use."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the contract described in the request, the customer has the right to direct the use of the specified underground space throughout the 20-year period of use because the conditions in paragraph B24(b)(i) exist. How and for what purpose the specified underground space will be used (ie to locate the pipeline with specified dimensions through which oil will be transported) is predetermined in the contract. The customer has the right to operate the specified underground space by having the right to perform inspection, repairs and maintenance work. The customer makes all the decisions about the use of the specified underground space that can be made during the 20-year period of use."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee concluded that the contract described in the request contains a lease as defined in IFRS 16. The customer would therefore apply IFRS 16 in accounting for that lease."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity to determine its accounting for the contract described in the request. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function u(e={}){let{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},28453(e,t,i){i.d(t,{R:()=>o,x:()=>r});var s=i(96540);let a={},n=s.createContext(a);function o(e){let t=s.useContext(n);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),s.createElement(n.Provider,{value:t},e.children)}}}]);